#include <iostream>
#include <memory>
#include <string>
#include <vector>

class Animal
{
    std::string m_name;

public:
    Animal(std::string name) : m_name{ std::move(name) } {}
    virtual ~Animal() = default;
    const std::string& getName() const { return m_name; }
    virtual std::string speak() const = 0;
};

class Pet
{
public:
    virtual ~Pet() = default;
    virtual std::string trick() const = 0;
};

class Dog : public Animal, public Pet
{
public:
    Dog(std::string name) : Animal{ std::move(name) } {}
    std::string speak() const override { return getName() + " says Woof!"; }
    std::string trick() const override { return "fetch"; }
};

class Cat : public Animal, public Pet
{
public:
    Cat(std::string name) : Animal{ std::move(name) } {}
    std::string speak() const override { return getName() + " says Meow!"; }
    std::string trick() const override { return "purr"; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<Animal>> animals;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{}, name{};
        std::cin >> type >> name;

        if (type == "dog")
            animals.push_back(std::make_unique<Dog>(std::move(name)));
        else
            animals.push_back(std::make_unique<Cat>(std::move(name)));
    }

    for (const auto& a : animals)
        std::cout << a->speak() << '\n';

    std::cout << '\n';

    int petCount{ 0 };
    for (const auto& a : animals)
    {
        Pet* pet{ dynamic_cast<Pet*>(a.get()) };
        if (pet)
        {
            std::cout << a->getName() << " is a pet (trick: " << pet->trick() << ")\n";
            ++petCount;
        }
    }

    std::cout << "Pets found: " << petCount << '\n';

    return 0;
}
